"use server";

import { revalidatePath } from "next/cache";
import { requireAuthContext } from "@/lib/firebase/auth";
import { uploadWorkspaceFile } from "@/lib/firebase/storage";
import { skillsRepository } from "@/lib/repositories/skills-repository";

export async function createSkill(formData: FormData): Promise<void> {
  const auth = await requireAuthContext();
  const item = await skillsRepository.create(auth.workspaceId, {
    name: String(formData.get("name") || "Untitled"),
    prompt: String(formData.get("prompt") || ""),
    createdBy: auth.userId,
  });

  const file = formData.get("fileContent");
  if (typeof file === "string" && file.length) {
    await uploadWorkspaceFile({
      workspaceId: auth.workspaceId,
      entityType: "skill",
      entityId: item.id,
      content: file,
      authorId: auth.userId,
    });
  }

  revalidatePath("/skills");
}
